"use strict";(globalThis.webpackChunkratel_docs=globalThis.webpackChunkratel_docs||[]).push([[567],{5226(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"docsSidebar":[{"type":"link","href":"/","label":"About Ratel","docId":"intro/index","unlisted":false},{"type":"link","href":"/getting-started","label":"Getting Started","docId":"getting-started","unlisted":false},{"type":"category","label":"Teams","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/teams/create","label":"Create a Team","docId":"teams/create","unlisted":false},{"type":"link","href":"/teams/sub-teams","label":"Sub-teams","docId":"teams/sub-teams","unlisted":false},{"type":"link","href":"/teams/team-settings","label":"Team Settings","docId":"teams/team-settings","unlisted":false}],"href":"/teams/"},{"type":"link","href":"/posts","label":"Posts","docId":"posts","unlisted":false},{"type":"category","label":"Spaces","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/spaces/apps","label":"Space Apps (Host Tools)","docId":"spaces/apps","unlisted":false},{"type":"link","href":"/spaces/actions","label":"Space Actions","docId":"spaces/actions","unlisted":false},{"type":"link","href":"/spaces/dashboard","label":"Space Dashboard (Host)","docId":"spaces/dashboard","unlisted":false},{"type":"link","href":"/spaces/host-actions","label":"Host Actions (Editors)","docId":"spaces/host-actions","unlisted":false},{"type":"link","href":"/spaces/reports","label":"Reports (Host)","docId":"spaces/reports","unlisted":false}],"href":"/spaces"},{"type":"category","label":"Essence","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/essence/my-essence","label":"My Essence","docId":"essence/my-essence","unlisted":false},{"type":"link","href":"/essence/sources","label":"Essence Sources","docId":"essence/sources","unlisted":false}],"href":"/essence/"},{"type":"category","label":"Rewards","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/rewards/xp","label":"Experience Points (XP)","docId":"rewards/xp","unlisted":false},{"type":"link","href":"/rewards/points","label":"Reward Points","docId":"rewards/points","unlisted":false},{"type":"link","href":"/rewards/credits","label":"Credits","docId":"rewards/credits","unlisted":false},{"type":"link","href":"/rewards/tokens","label":"Tokens","docId":"rewards/tokens","unlisted":false},{"type":"link","href":"/rewards/incentives","label":"Incentive Pool","docId":"rewards/incentives","unlisted":false}],"href":"/rewards/"},{"type":"category","label":"Credentials","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/credentials/attributes","label":"Attribute management","docId":"credentials/attributes","unlisted":false}],"href":"/credentials/"}]},"docs":{"credentials/attributes":{"id":"credentials/attributes","title":"Attribute management","description":"This page is the hands-on guide to the /credentials surface \u2014 the layout you\'ll see, the two verification methods (KYC and offline codes), the attribute slots Ratel supports today, and the cryptographic proof underneath. For why credentials matter and where they\'re used, see the Credentials overview.","sidebar":"docsSidebar"},"credentials/index":{"id":"credentials/index","title":"Credentials","description":"A Credential on Ratel is a verifiable claim about you \u2014 your age, your affiliation with an institution, a one-time code an organizer handed out at a conference \u2014 bound to your decentralized identifier (DID) and signed by Ratel Foundation. Together, your DID and the credentials attached to it form a privacy-preserving identity wallet you can selectively disclose to Spaces, Teams, and external verifiers.","sidebar":"docsSidebar"},"essence/index":{"id":"essence/index","title":"Essence","description":"Your Essence is a personal knowledge base that grows from the things you do on Ratel \u2014 every post you publish, every comment you write, every poll or quiz you host, every action you complete in a Space. The platform turns each of these into an EssenceSource: a structured record indexed for retrieval, attributed to your account, and (later) embedded into a vector representation that an AI assistant can query.","sidebar":"docsSidebar"},"essence/my-essence":{"id":"essence/my-essence","title":"My Essence","description":"Your Essence isn\'t an abstract concept \u2014 it\'s a real surface in the app, with two dedicated pages where you see what you\'ve built and what it earns you. My AI at /my-ai is where you connect Ratel to your AI assistant. Character at /me/character is where your activity becomes a level, skill points, and stat boosts you can spend.","sidebar":"docsSidebar"},"essence/sources":{"id":"essence/sources","title":"Essence Sources","description":"Your Essence has a control panel \u2014 one page where you can see every input feeding it, search across them, and clean out anything you no longer want. It lives at:","sidebar":"docsSidebar"},"getting-started":{"id":"getting-started","title":"Getting Started","description":"Welcome to Ratel \u2014 the Human Essence Platform. This chapter walks you through your first day: signing in, setting up your profile, connecting external accounts, and finding your way around.","sidebar":"docsSidebar"},"intro/index":{"id":"intro/index","title":"About Ratel","description":"Ratel is a Human Essence Platform. It\'s a place where the thoughts, insights, and activities of real people are captured, embedded, and turned into a personal asset you can use, share, and monetize. Every post you write, every space you join, every vote, comment, and discussion you take part in becomes part of your Essence \u2014 a personal knowledge base that grows as you participate.","sidebar":"docsSidebar"},"posts":{"id":"posts","title":"Posts","description":"Why posts matter","sidebar":"docsSidebar"},"rewards/credits":{"id":"rewards/credits","title":"Credits","description":"Credits are the host-funded currency that backs an Action\'s reward in a Space. They\'re the upstream of Reward Points: when a host configures an Action\'s reward, they allocate Credits from their Incentive Pool \u2014 and at payout, each Credit converts into Points for the participant who earned it.","sidebar":"docsSidebar"},"rewards/incentives":{"id":"rewards/incentives","title":"Incentive Pool","description":"The Incentive Pool is the host-side funding surface \u2014 what stages reward currency before it\'s attached to individual Actions. It\'s where a Space\'s reward economy starts: the host loads the pool with Credits, configures distribution rules, and the pool then pays out to participants as Actions complete.","sidebar":"docsSidebar"},"rewards/index":{"id":"rewards/index","title":"Rewards","description":"The Ratel rewards economy turns activity into value through five distinct primitives, each with its own purpose:","sidebar":"docsSidebar"},"rewards/points":{"id":"rewards/points","title":"Reward Points","description":"Reward Points (pts) are Ratel\'s in-platform reputation unit and the unit of earning across reward-bearing Spaces. Where XP measures your progression, Points measure your take-home \u2014 they accumulate inside a cycle, feed your Direct-Activity Index, and (at month-end) lock in as a claimable Token amount.","sidebar":"docsSidebar"},"rewards/tokens":{"id":"rewards/tokens","title":"Tokens","description":"Tokens are the on-chain expression of a past cycle\'s Reward Points. Where Points are off-platform-chain bookkeeping, Tokens are blockchain-native assets you claim into a wallet you control. They settle the platform\'s promise that participation has value \u2014 and they\'re 100% backed by a treasury reserve.","sidebar":"docsSidebar"},"rewards/xp":{"id":"rewards/xp","title":"Experience Points (XP)","description":"XP is the activity-driven progression unit that powers your Character on Ratel. Every Space action you complete records a SpaceActivity row, and that row mints a fixed XP amount into your Character total. XP doesn\'t directly cash out \u2014 its job is to drive your level, your Skill Points (SP), and the boosts you spend SP on.","sidebar":"docsSidebar"},"spaces/actions":{"id":"spaces/actions","title":"Space Actions","description":"If Apps are the host\'s toolkit, Actions are the participant\'s quest board. Each Action is a single thing the host wants you to do \u2014 vote on something, weigh in on a discussion, answer a quiz, follow a few accounts, RSVP to a meet \u2014 and finishing it earns you a share of the Space\'s rewards while feeding your Essence with structured signal about what you think.","sidebar":"docsSidebar"},"spaces/apps":{"id":"spaces/apps","title":"Space Apps (Host Tools)","description":"If you\'re the host of a Space, Apps are the building blocks you plug in to shape it. Each App handles one job \u2014 publishing info, sharing files, asking participants to vote, generating an AI-assisted report, distributing rewards \u2014 and the App you don\'t need today, you simply leave out.","sidebar":"docsSidebar"},"spaces/dashboard":{"id":"spaces/dashboard","title":"Space Dashboard (Host)","description":"The Dashboard is the host\'s \\"how is my Space doing today\\" view \u2014 a stat-card grid plus a participant ranking, all driven directly off live activity. It lives at:","sidebar":"docsSidebar"},"spaces/host-actions":{"id":"spaces/host-actions","title":"Host Actions (Editors)","description":"This chapter is the host-side companion to Space Actions. The participant chapter explains what an Action looks like to someone who shows up to engage; this one walks you, the host, through creating and editing each Action type.","sidebar":"docsSidebar"},"spaces/index":{"id":"spaces/index","title":"Spaces","description":"A Space is the arena where Ratel activity happens. Discussions, polls, quizzes, follow quests, scheduled meets \u2014 everything that turns a community into a measurable conversation lives inside a Space. From a Space, hosts shape what participants see, and participants accumulate Essence as they engage.","sidebar":"docsSidebar"},"spaces/reports":{"id":"spaces/reports","title":"Reports (Host)","description":"A Report is the host\'s published synthesis of what happened in their Space \u2014 what participants thought, where they agreed, where they didn\'t, what stood out. Ratel ships two report surfaces that work together:","sidebar":"docsSidebar"},"teams/create":{"id":"teams/create","title":"Create a Team","description":"This page walks you through creating a team and getting it set up \u2014 the popup, the arena tabs you\'ll see once you land, the member roles, the publishing surfaces (posts / drafts / rewards / memberships), team subscription, the built-in DAO, and a brief index of sub-team flows. For the broader context \u2014 what teams are and where the chapter goes next \u2014 see the Teams overview.","sidebar":"docsSidebar"},"teams/index":{"id":"teams/index","title":"Teams","description":"A Team on Ratel is a multi-author collaboration unit with its own handle, its own arena pages, and its own treasury \u2014 so the work you do collectively is attributed to the team, not just the people inside it. Teams publish posts, run reward Spaces, distribute earnings, and govern themselves through a built-in DAO.","sidebar":"docsSidebar"},"teams/sub-teams":{"id":"teams/sub-teams","title":"Sub-teams","description":"Sub-teams are how a parent Team formally recognizes another Team as part of its umbrella \u2014 a chapter, a working group, a partner cell \u2014 without absorbing it. Each side keeps its own posts, members, treasury, and Spaces, but the relationship is an on-platform link with rules, documents, announcements, and a public registry of who belongs to whom.","sidebar":"docsSidebar"},"teams/team-settings":{"id":"teams/team-settings","title":"Team Settings","description":"Team Settings is where a Team\'s admins manage the Team itself \u2014 its public identity, its members and roles, the subscription paying for its monthly Credits, and (if it comes to it) the deletion flow. This is the administrator\'s view of a Team; for the public profile and feed, see Create a Team.","sidebar":"docsSidebar"}}}}')}}]);